import java.io.*;

public class Main {
    public static void main(String[] args) {
        // Writing bytes
        try (FileOutputStream fos = new FileOutputStream("data.dat")) {
            byte[] data = {65, 66, 67, 68};  // A, B, C, D
            fos.write(data);
            System.out.println("Bytes written");
        } catch (IOException e) {
            e.printStackTrace();
        }

        // Reading bytes
        try (FileInputStream fis = new FileInputStream("data.dat")) {
            int byteData;
            while ((byteData = fis.read()) != -1) {
                System.out.print((char) byteData + " ");
            }
        } catch (IOException e) {
            e.printStackTrace();
        }

        // Using buffered streams
        try (BufferedWriter bw = new BufferedWriter(new FileWriter("text.txt"))) {
            bw.write("Hello Buffered World");
            bw.newLine();
            bw.write("Second line");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}
